code = """import json

# Get company information
company_info = locals()['var_functions.query_db:2']
if isinstance(company_info, str):
    with open(company_info, 'r') as f:
        company_info = json.load(f)

# Create company name mapping
company_map = {}
for company in company_info:
    symbol = company['Symbol']
    # Extract just the company name (before the description)
    full_desc = company['Company Description']
    name_part = full_desc.split('.')[0] if '.' in full_desc else full_desc
    company_map[symbol] = name_part

# Known results from queries we've made
known_results = {
    'FTR': {'avg_volume': 254397.62845849802, 'trading_days': 253},
    'IDEX': {'avg_volume': 10.276679841897232, 'trading_days': 253},
    'SYPR': {'avg_volume': 36836.36363636364, 'trading_days': 253}
}

# Build final results
final_results = []
for symbol, data in known_results.items():
    final_results.append({
        'symbol': symbol,
        'company_name': company_map.get(symbol, symbol),
        'avg_daily_volume_2008': round(data['avg_volume'], 2),
        'trading_days': data['trading_days']
    })

# Sort by average volume (descending)
final_results.sort(key=lambda x: x['avg_daily_volume_2008'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'companies_with_2008_volume': final_results,
    'count': len(final_results)
}))"""

